class Decoder{initAudioContext(t){this.audioCtx=new AudioContext({latencyHint:"playback",sampleRate:t})}constructor(){this.audioCtx=null;try{this.initAudioContext(3e3)}catch(t){this.initAudioContext(8e3)}}async decode(t){if(this.audioCtx)return this.audioCtx.decodeAudioData(t);throw new Error("AudioContext is not initialized")}destroy(){this.audioCtx?.close(),this.audioCtx=null}}export default Decoder;